import { describe, it, expect } from 'vitest';
import { MessageBus } from '../src/services/message-bus.js';

/**
 * Micro-benchmark for the message-bus publish hot path.
 *
 * Regression guard: publish() must NOT allocate a fresh array copy of all
 * subscriptions per event (the old `Array.from(this.subscriptions.values())`)
 * and must reuse pre-split topic pattern segments cached on each subscription
 * instead of re-splitting every pattern on every publish. This keeps per-event
 * work O(N) over matched subscribers with zero per-call array/string churn.
 */
describe('message-bus publish hot-path benchmark', () => {
  it('publishes 5000 events to 50 subscribers with p95 latency under threshold', async () => {
    const bus = new MessageBus();
    const deliveries: number[] = [];
    const N = 50;
    for (let i = 0; i < N; i++) {
      const slot = i;
      await bus.subscribe(`sub-${i}`, 'metrics/agent/#', (msg) => {
        deliveries[slot] = (deliveries[slot] ?? 0) + 1;
      });
    }

    const iterations = 5000;
    const latencies: number[] = [];
    for (let i = 0; i < iterations; i++) {
      const start = performance.now();
      await bus.publish('metrics/agent/cpu', { v: i });
      latencies.push(performance.now() - start);
    }

    // Every subscriber matched the '#' wildcard pattern.
    for (let i = 0; i < N; i++) {
      expect(deliveries[i]).toBe(iterations);
    }

    latencies.sort((a, b) => a - b);
    const p95 = latencies[Math.floor(latencies.length * 0.95)];
    expect(p95).toBeLessThan(50);

    const avg = latencies.reduce((s, v) => s + v, 0) / latencies.length;
    // eslint-disable-next-line no-console
    console.log(
      `[message-bus bench] subs=${N} iters=${iterations} avg=${avg.toFixed(4)}ms p95=${p95.toFixed(4)}ms`
    );
  });

  it('does not allocate a per-publish array copy of subscribers', async () => {
    const bus = new MessageBus();
    await bus.subscribe('a', 'x/#', () => {});
    // A publish with a topic that matches nothing still exercises the
    // iteration loop; the key assertion is that it completes without error
    // and that no exception escapes from the hot path.
    await bus.publish('y/z', { hello: 'world' });
    expect(true).toBe(true);
  });
});

import { describe, it, expect } from 'vitest';
import {
  addSSEClient,
  broadcastSSE,
  getSSEClientCount,
} from '../src/services/sse-bus.js';

/**
 * Micro-benchmark: SSE fan-out must stay O(N) publish, not O(N^2).
 *
 * We spin up N synthetic subscribers (each buffering the last write), then
 * measure per-publish latency and assert p95 stays under a generous threshold
 * so the test is meaningful on any CI runner while still catching quadratic
 * regressions (which would blow the budget at 100 subscribers).
 */
function makeClient() {
  const buf: string[] = [];
  return {
    writes: 0,
    write(chunk: string) {
      buf.push(chunk);
      this.writes++;
    },
    close() {},
    last: () => buf[buf.length - 1],
  };
}

describe('sse-bus fan-out benchmark', () => {
  it('publishes to 100 subscribers with p95 latency under threshold', () => {
    const N = 100;
    const clients = Array.from({ length: N }, () => makeClient());
    const removeFns = clients.map((c) => addSSEClient(c));

    expect(getSSEClientCount()).toBe(N);

    const iterations = 200;
    const latencies: number[] = [];
    for (let i = 0; i < iterations; i++) {
      const start = performance.now();
      broadcastSSE({ type: 'tick', data: { i }, timestamp: Date.now() });
      latencies.push(performance.now() - start);
    }

    // Basic correctness: every client received every message.
    for (const c of clients) {
      expect(c.writes).toBe(iterations);
    }

    latencies.sort((a, b) => a - b);
    const p95 = latencies[Math.floor(latencies.length * 0.95)];
    // Generous ceiling — catches O(N^2) regressions (which would be orders of
    // magnitude slower) without being flaky on slow CI. Fan-out is pure
    // in-memory writes here, so the real cost is tiny.
    expect(p95).toBeLessThan(50);

    const avg = latencies.reduce((s, v) => s + v, 0) / latencies.length;
    // eslint-disable-next-line no-console
    console.log(
      `[sse-bus bench] N=${N} iters=${iterations} avg=${avg.toFixed(4)}ms p95=${p95.toFixed(4)}ms`
    );

    removeFns.forEach((fn) => fn());
    expect(getSSEClientCount()).toBe(0);
  });

  it('prunes a failing client on broadcast without breaking the fan-out', () => {
    const good = makeClient();
    const bad = {
      writes: 0,
      write() {
        throw new Error('closed');
      },
      close() {},
    };
    const removeGood = addSSEClient(good);
    const removeBad = addSSEClient(bad);

    // First broadcast: bad throws, gets pruned, good still receives.
    broadcastSSE({ type: 'a', data: 1, timestamp: Date.now() });
    expect(good.writes).toBe(1);

    // Second broadcast: bad is gone, only good remains.
    broadcastSSE({ type: 'b', data: 2, timestamp: Date.now() });
    expect(good.writes).toBe(2);

    removeGood();
    removeBad();
    expect(getSSEClientCount()).toBe(0);
  });
});

