describe('Forge — live pre-pick MLFQ aging pass (enqueue/promote/demote at dispatch)', () => {
  const now = 1_000_000_000_000;
  function q(id: string, queue: string, ageMs: number): any {
    return {
      id,
      agentId: 'a',
      queue,
      priority: 0,
      deadline: null,
      createdAt: new Date(now - ageMs),
      kind: 'task.run',
    };
  }

  it('promotes a sufficiently-aged task one level toward Q0', () => {
    const pool = [q('t1', 'Q2', MLFQ_AGE_PROMOTE_MS + 1000)];
    const changed = applyMlfqAgingPass(pool, now);
    expect(changed).toEqual([{ id: 't1', from: 'Q2', to: 'Q0' }]);
    expect(pool[0].queue).toBe('Q0');
  });

  it('does not promote a young task', () => {
    const pool = [q('t1', 'Q3', MLFQ_AGE_PROMOTE_MS - 5000)];
    const changed = applyMlfqAgingPass(pool, now);
    expect(changed.length).toBe(0);
    expect(pool[0].queue).toBe('Q3');
  });

  it('does not promote a task already at Q0', () => {
    const pool = [q('t1', 'Q0', MLFQ_AGE_PROMOTE_MS + 99999)];
    const changed = applyMlfqAgingPass(pool, now);
    expect(changed.length).toBe(0);
  });

  it('promotes each aged task independently toward Q0', () => {
    const pool = [
      q('a', 'Q4', MLFQ_AGE_PROMOTE_MS + 1),
      q('b', 'Q1', MLFQ_AGE_PROMOTE_MS + 1),
      q('c', 'Q0', MLFQ_AGE_PROMOTE_MS + 1), // already at top → unchanged
      q('d', 'Q3', 10), // young → unchanged
    ];
    const changed = applyMlfqAgingPass(pool, now);
    expect(changed.map((c) => c.id).sort()).toEqual(['a', 'b']);
    expect(pool.find((t) => t.id === 'a').queue).toBe('Q0');
    expect(pool.find((t) => t.id === 'b').queue).toBe('Q0');
    expect(pool.find((t) => t.id === 'c').queue).toBe('Q0');
    expect(pool.find((t) => t.id === 'd').queue).toBe('Q3');
  });

  it('promotion counter getter returns a number (kernel increments by changed.length)', () => {
    expect(typeof getMlfqPromotionCount()).toBe('number');
    const pool = [
      q('a', 'Q4', MLFQ_AGE_PROMOTE_MS + 1),
      q('b', 'Q2', MLFQ_AGE_PROMOTE_MS + 1),
      q('c', 'Q3', 10),
    ];
    const changed = applyMlfqAgingPass(pool, now);
    expect(changed.length).toBe(2);
  });
});

/**
 * tests/helpers/db-setup.ts — Clean temporary SQLite test database fixture.
 *
 * Creates a fresh SQLite database in a temp directory, applies the full
 * schema from the drizzle migration, and returns db + table references.
 *
 * Usage:
 * ```ts
 * import { createTestDb, closeTestDb } from './helpers/db-setup.js';
 *
 * const { db, memories } = await createTestDb();
 * await db.insert(memories).values({ id: crypto.randomUUID(), ... });
 * // ... run tests ...
 * await closeTestDb();
 * ```
 */

import { createRequire } from 'node:module';
import { existsSync, unlinkSync, mkdtempSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { readFileSync } from 'node:fs';

const require = createRequire(import.meta.url);
const Database = require('better-sqlite3');

let _sqliteDb: ReturnType<typeof Database> | null = null;
let _testDbPath: string | null = null;

export interface TestDbFixtures {
  db: any;
  apiKeys: any;
  memories: any;
  agents: any;
  projects: any;
  skills: any;
  compiledScripts: any;
  notes: any;
  conversations: any;
  messages: any;
  agentTasks: any;
  trajectoryLogs: any;
  auditLog: any;
  mcpServers: any;
  pipelines: any;
  pipelineSteps: any;
  vaultEntries: any;
  metricSnapshots: any;
  improvementProposals: any;
  performanceReports: any;
  userFeedback: any;
  feedbackTags: any;
  guardianRules: any;
  sessions: any;
  events: any;
  subscriptions: any;
  apiKeyUsage: any;
}

/**
 * Create a fresh temporary SQLite test database with full schema.
 */
export async function createTestDb(migrationSqlPath?: string): Promise<TestDbFixtures> {
  const tmpDir = mkdtempSync(join(tmpdir(), 'nexus-test-'));
  _testDbPath = join(tmpDir, 'test.db');

  _sqliteDb = new Database(_testDbPath, {});
  _sqliteDb.pragma('journal_mode = WAL');
  _sqliteDb.pragma('busy_timeout = 5000');
  _sqliteDb.pragma('synchronous = NORMAL');

  // Load the schema module to get table references
  const schema = await import('../../src/db/schema-sqlite.js');
  const { drizzle } = await import('drizzle-orm/better-sqlite3');

  // Run the migration SQL to create all tables
  const migrationPath =
    migrationSqlPath ?? join(process.cwd(), 'drizzle', '0000_dark_misty_knight.sql');
  if (existsSync(migrationPath)) {
    const sql = readFileSync(migrationPath, 'utf-8');
    // Split on statement-breakpoint comments and execute each
    const statements = sql.split('--> statement-breakpoint');
    for (const stmt of statements) {
      const trimmed = stmt.trim();
      if (trimmed) {
        try {
          _sqliteDb.exec(trimmed);
        } catch (err) {
          // Ignore "already exists" errors in case of idempotent runs
          const msg = String(err);
          if (!msg.includes('already exists')) throw err;
        }
      }
    }
  }

  const db = drizzle(_sqliteDb, { schema });

  return {
    db,
    apiKeys: schema.apiKeys,
    memories: schema.memories,
    agents: schema.agents,
    projects: schema.projects,
    skills: schema.skills,
    compiledScripts: schema.compiledScripts,
    notes: schema.notes,
    conversations: (schema as any).conversations ?? {},
    messages: (schema as any).messages ?? {},
    agentTasks: schema.agentTasks,
    trajectoryLogs: schema.trajectoryLogs,
    auditLog: schema.auditLog,
    mcpServers: (schema as any).mcpServers ?? {},
    pipelines: schema.pipelines,
    pipelineSteps: (schema as any).pipelineSteps ?? {},
    vaultEntries: (schema as any).vaultEntries ?? {},
    metricSnapshots: schema.metricSnapshots,
    improvementProposals: schema.improvementProposals,
    performanceReports: (schema as any).performanceReports ?? {},
    userFeedback: schema.feedback,
    feedbackTags: (schema as any).feedbackTags ?? {},
    guardianRules: (schema as any).guardianRules ?? {},
    sessions: (schema as any).sessions ?? {},
    events: (schema as any).events ?? {},
    subscriptions: (schema as any).subscriptions ?? {},
    apiKeyUsage: (schema as any).apiKeyUsage ?? {},
  };
}

/**
 * Close and remove the test database.
 */
export async function closeTestDb(): Promise<void> {
  if (_sqliteDb) {
    try {
      _sqliteDb.close();
    } catch {
      /* ignore */
    }
    _sqliteDb = null;
  }
  if (_testDbPath) {
    for (const suffix of ['', '-wal', '-shm']) {
      const p = _testDbPath + suffix;
      try {
        if (existsSync(p)) unlinkSync(p);
      } catch {
        /* best-effort */
      }
    }
    _testDbPath = null;
  }
}

/**
 * tests/helpers/mock-llm.ts — Deterministic LLM provider mock for offline testing.
 *
 * Replaces the real LLM client with a fake that returns controlled responses.
 * This enables testing of LLM-dependent services without API keys or network.
 *
 * Usage:
 * ```ts
 * import { mockLlm } from './helpers/mock-llm.js';
 *
 * const llm = mockLlm({ defaultResponse: 'Hello world' });
 * const reply = await llm.chat([{ role: 'user', content: 'Hi' }]);
 * expect(reply.content).toBe('Hello world');
 * ```
 */

export type MessageRole = 'system' | 'user' | 'assistant' | 'tool';

export interface ChatMessage {
  role: MessageRole;
  content: string;
  name?: string;
  tool_call_id?: string;
}

export interface MockLlmResponse {
  content: string;
  model?: string;
  usage?: { promptTokens: number; completionTokens: number; totalTokens: number };
  toolCalls?: Array<{ name: string; arguments: Record<string, unknown> }>;
  finishReason?: 'stop' | 'tool_calls' | 'length';
}

export interface MockLlmConfig {
  /** Default response content for simple chats */
  defaultResponse?: string;
  /** Map of prompt → response for deterministic matching */
  responseMap?: Map<string, MockLlmResponse>;
  /** Default response object */
  defaultResponseObj?: MockLlmResponse;
  /** Simulated latency in ms (default: 0) */
  latencyMs?: number;
  /** Model name reported in responses (default: 'mock-model') */
  modelName?: string;
  /** Throw an error on any request (for testing error paths) */
  shouldThrow?: Error;
  /** Callback fired on each request (for assertions) */
  onRequest?: (messages: ChatMessage[]) => void;
}

/**
 * Create a mock LLM client that implements the standard chat interface.
 */
export function mockLlm(config: MockLlmConfig = {}) {
  const {
    defaultResponse = 'Mock response',
    responseMap = new Map(),
    latencyMs = 0,
    modelName = 'mock-model',
    shouldThrow,
    onRequest,
  } = config;

  const defaultResponseObj: MockLlmResponse = config.defaultResponseObj ?? {
    content: defaultResponse,
    model: modelName,
    usage: { promptTokens: 10, completionTokens: 20, totalTokens: 30 },
    finishReason: 'stop',
  };

  async function chat(
    messages: ChatMessage[],
    _options?: { tools?: any[]; stream?: boolean }
  ): Promise<MockLlmResponse> {
    // Fire callback for assertions
    onRequest?.(messages);

    // Simulate latency
    if (latencyMs > 0) {
      await new Promise((r) => setTimeout(r, latencyMs));
    }

    // Check if should throw
    if (shouldThrow) {
      throw shouldThrow;
    }

    // Check response map by joining message content
    const promptKey = messages.map((m) => `${m.role}:${m.content}`).join('||');
    const mapped = responseMap.get(promptKey);
    if (mapped) return { ...mapped, model: modelName };

    return { ...defaultResponseObj };
  }

  async function chatStream(
    messages: ChatMessage[],
    options?: { tools?: any[] }
  ): Promise<AsyncIterable<string>> {
    if (shouldThrow) throw shouldThrow;

    const response = await chat(messages, options);
    return {
      [Symbol.asyncIterator]() {
        let idx = 0;
        const chunks = response.content.split(/(?<=\s)/);
        return {
          async next(): Promise<IteratorResult<string>> {
            if (idx >= chunks.length) return { done: true, value: undefined as any };
            if (latencyMs > 0) await new Promise((r) => setTimeout(r, latencyMs / chunks.length));
            return { done: false, value: chunks[idx++] ?? '' };
          },
        };
      },
    };
  }

  return {
    chat,
    chatStream,
    model: modelName,
    config,
    /** Reset the mock call history */
    reset() {
      callHistory.length = 0;
    },
    /** Get all requests made to this mock */
    getCallHistory() {
      return [...callHistory];
    },
  };
}

/** Global call history across all mock instances */
const callHistory: Array<{ messages: ChatMessage[]; timestamp: number }> = [];

export type MockLlmInstance = ReturnType<typeof mockLlm>;

/**
 * Create a mock LLM suite with multiple named instances.
 * Useful for testing multi-model workflows.
 */
export function mockLlmSuite(configs: Record<string, MockLlmConfig> = {}) {
  const instances = new Map<string, MockLlmInstance>();
  for (const [name, cfg] of Object.entries(configs)) {
    const wrappedCfg: MockLlmConfig = {
      ...cfg,
      onRequest(messages) {
        callHistory.push({ messages, timestamp: Date.now() });
        cfg.onRequest?.(messages);
      },
    };
    instances.set(name, mockLlm(wrappedCfg));
  }
  return {
    get(name: string): MockLlmInstance {
      const inst = instances.get(name);
      if (!inst) throw new Error(`Unknown mock LLM instance: ${name}`);
      return inst;
    },
    resetAll() {
      callHistory.length = 0;
    },
    getAllHistory() {
      return [...callHistory];
    },
  };
}

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { db, systemMeta } from '../src/db/client.js';
import {
  assertOperational,
  assertKillSwitchConsistent,
  isKillSwitchOn,
} from '../src/services/safety.service.js';
import { setKillSwitch } from '../src/services/session.service.js';

async function seedKillSwitch(initial: boolean) {
  await db
    .insert(systemMeta)
    .values({ key: 'killSwitch', value: initial ? '1' : '0', updatedAt: new Date() })
    .onConflictDoUpdate({
      target: systemMeta.key,
      set: { value: initial ? '1' : '0', updatedAt: new Date() },
    });
}

describe('Phase 1.7 — kill-switch race hardening', () => {
  beforeAll(async () => {
    await seedKillSwitch(false);
  });

  afterAll(async () => {
    await seedKillSwitch(false);
  });

  it('assertOperational passes while off and throws while on', async () => {
    await seedKillSwitch(false);
    await expect(assertOperational()).resolves.toBeUndefined();
    await seedKillSwitch(true);
    await expect(assertOperational()).rejects.toThrow(/Kill switch is engaged/);
  });

  it('double assert after kill-switch: re-read matches written state (engaged)', async () => {
    await seedKillSwitch(false);
    await setKillSwitch(true, 'race-test', 'sentinel');
    expect(await isKillSwitchOn()).toBe(true);
    // Inside a transaction the post-write guard must agree with the persisted value.
    await db.transaction(async (tx: any) => {
      await expect(assertKillSwitchConsistent(tx, true)).resolves.toBeUndefined();
      await expect(assertKillSwitchConsistent(tx, false)).rejects.toThrow(/diverged/);
    });
  });

  it('double assert after kill-switch: re-read matches written state (released)', async () => {
    await seedKillSwitch(true);
    await setKillSwitch(false, 'race-test-release', 'sentinel');
    expect(await isKillSwitchOn()).toBe(false);
    await db.transaction(async (tx: any) => {
      await expect(assertKillSwitchConsistent(tx, false)).resolves.toBeUndefined();
      await expect(assertKillSwitchConsistent(tx, true)).rejects.toThrow(/diverged/);
    });
  });

  it('setKillSwitch fully releases and is guarded by operational check', async () => {
    await seedKillSwitch(true);
    await setKillSwitch(false, undefined, 'sentinel');
    await expect(assertOperational()).resolves.toBeUndefined();
  });
});

