  });

  it('POST /api/v1/events/token should return a token for valid API keys', async () => {
    const { authenticate } = await import('../../src/lib/security.js');
    vi.mocked(authenticate as any).mockResolvedValue({
      id: 'p1',
      name: 'test',
      scopes: ['memory:read'],
