describe('harness applyPatch — live runtime-loop tuning', () => {
  beforeEach(() => {
    setSchedulingPolicy.mockClear();
    configureWorker.mockClear();
    findFirst.mockReset();
    findMany.mockReset();
    updateSet.mockReset();
