    createdAt: tsText('created_at')
      .notNull()
      .default(sql`(strftime('%Y-%m-%dT%H:%M:%fZ','now'))`),
    startedAt: safeText('started_at'),
    finishedAt: safeText('finished_at'),
  });

  const db = drizzle(sqliteDb, { schema: { agents, agentTasks } });
  testRef.db = db;
  testRef.agents = agents;
