    ).rejects.toBeInstanceOf(ResourceFuseTripped);
  });

  it('trips on fuel overage', async () => {
    await expect(
      withResourceFuse({ timeoutMs: 1000, maxFuel: 100 }, async () => 'ok', () => 500)
    ).rejects.toBeInstanceOf(ResourceFuseTripped);
  });

  it('does not trip when no getFuel provided', async () => {
